#!/usr/bin/env node
// QA Council - Budget Math Checks
// Generated by The Engineer (Agent 3). Validates budget calculations and structure.
// Usage: node budget-math-checks.js

var fs = require('fs');
var path = require('path');

var CONFIG = {
  basePath: '/sessions/sleepy-gifted-allen/mnt/site/builder',
  budgetSetupFile: 'js/budget-setup.js',
  budgetIntegrationFile: 'js/budget-integration.js',
  htmlFile: 'index.html'
};

var results = [];
var passed = 0;
var failed = 0;

function assert(condition, testName, details) {
  if (condition) {
    console.log('[PASS] ' + testName);
    passed++;
  } else {
    console.log('[FAIL] ' + testName + (details ? ': ' + details : ''));
    failed++;
  }
  results.push({ test: testName, passed: condition, details: details || '' });
}

// ============================================================================
// TEST 1: FUNDING_SOURCES Completeness
// ============================================================================
function testFundingSources() {
  console.log('\n--- Funding Sources ---');
  var setupPath = path.join(CONFIG.basePath, CONFIG.budgetSetupFile);
  if (!fs.existsSync(setupPath)) {
    assert(false, 'budget-setup.js exists', 'File not found');
    return;
  }

  var content = fs.readFileSync(setupPath, 'utf8');

  // Extract funding source keys from FUNDING_SOURCES definition (array pattern)
  var fundingSourcesRegex = /var\s+FUNDING_SOURCES\s*=\s*\[([\s\S]*?)\];/;
  var match = fundingSourcesRegex.exec(content);

  if (!match) {
    assert(false, 'FUNDING_SOURCES defined', 'Could not find FUNDING_SOURCES definition');
    return;
  }

  var fundingBlock = match[1];
  var expectedSources = [
    'title_i', 'title_ii', 'title_iii', 'title_iv', 'idea', 'esser',
    'general_fund', 'state_allocation', 'federal_grant', 'local_grant', 'bond_capital', 'other'
  ];

  var foundCount = 0;
  expectedSources.forEach(function(source) {
    if (fundingBlock.includes("'" + source + "'") || fundingBlock.includes('"' + source + '"')) {
      foundCount++;
    }
  });

  assert(foundCount === expectedSources.length, 'FUNDING_SOURCES has 12 sources', 'Found ' + foundCount + '/12 sources');
}

// ============================================================================
// TEST 2: Key Functions Exist
// ============================================================================
function testFunctionExistence() {
  console.log('\n--- Function Existence ---');
  var setupPath = path.join(CONFIG.basePath, CONFIG.budgetSetupFile);
  var integrationPath = path.join(CONFIG.basePath, CONFIG.budgetIntegrationFile);

  if (!fs.existsSync(setupPath)) {
    assert(false, 'budget-setup.js exists', 'File not found');
    return;
  }

  if (!fs.existsSync(integrationPath)) {
    assert(false, 'budget-integration.js exists', 'File not found');
    return;
  }

  var setupContent = fs.readFileSync(setupPath, 'utf8');
  var integrationContent = fs.readFileSync(integrationPath, 'utf8');

  var setupFunctions = [
    'renderBudgetSetup', 'recalculateBudgetTotals', 'getBudgetEnvelope',
    'getRemainingBudget', 'saveBudgetSetup'
  ];

  var integrationFunctions = [
    'renderGoalBudgetContext', 'renderBudgetAllocationTracker',
    'calculateFeasibilityScore'
  ];

  setupFunctions.forEach(function(fn) {
    var found = setupContent.includes('function ' + fn) || setupContent.includes('var ' + fn + ' = function');
    assert(found, 'Function defined: ' + fn + ' (budget-setup.js)');
  });

  integrationFunctions.forEach(function(fn) {
    var found = integrationContent.includes('function ' + fn) || integrationContent.includes('var ' + fn + ' = function');
    assert(found, 'Function defined: ' + fn + ' (budget-integration.js)');
  });
}

// ============================================================================
// TEST 3: Window Exports
// ============================================================================
function testWindowExports() {
  console.log('\n--- Window Exports ---');
  var setupPath = path.join(CONFIG.basePath, CONFIG.budgetSetupFile);
  var integrationPath = path.join(CONFIG.basePath, CONFIG.budgetIntegrationFile);

  var setupContent = fs.readFileSync(setupPath, 'utf8');
  var integrationContent = fs.readFileSync(integrationPath, 'utf8');
  var combined = setupContent + integrationContent;

  var requiredExports = [
    'renderBudgetSetup', 'getBudgetEnvelope', 'getRemainingBudget',
    'renderGoalBudgetContext', 'renderBudgetAllocationTracker',
    'calculateFeasibilityScore'
  ];

  var foundCount = 0;
  requiredExports.forEach(function(fn) {
    if (combined.includes('window.' + fn) || combined.includes('exports.' + fn)) {
      foundCount++;
    }
  });

  assert(foundCount >= 5, 'Key functions exported to window', 'Found ' + foundCount + '/6 required exports');
}

// ============================================================================
// TEST 4: Feasibility Score Weights Validation
// ============================================================================
function testFeasibilityWeights() {
  console.log('\n--- Feasibility Weights ---');
  var integrationPath = path.join(CONFIG.basePath, CONFIG.budgetIntegrationFile);
  var content = fs.readFileSync(integrationPath, 'utf8');

  // Look for weight definitions in calculateFeasibilityScore using multiplication pattern
  // Pattern: (scores.budget * 0.30) + (scores.priority * 0.25) + (scores.sustainability * 0.25) + (scores.coverage * 0.20)
  var weightRegex = /scores\.budget\s*\*\s*([0-9.]+)\s*\)\s*\+\s*\([^)]*scores\.priority\s*\*\s*([0-9.]+)\s*\)\s*\+\s*\([^)]*scores\.sustainability\s*\*\s*([0-9.]+)\s*\)\s*\+\s*\([^)]*scores\.coverage\s*\*\s*([0-9.]+)/;
  var match = weightRegex.exec(content);

  if (match) {
    var w1 = parseFloat(match[1]);
    var w2 = parseFloat(match[2]);
    var w3 = parseFloat(match[3]);
    var w4 = parseFloat(match[4]);
    var total = w1 + w2 + w3 + w4;

    // Weights should sum to 1.0, allowing small floating point tolerance
    assert(Math.abs(total - 1.0) < 0.01, 'Feasibility weights sum to ~1.0', 'Actual sum: ' + total.toFixed(3));
  } else {
    assert(false, 'Feasibility weights sum to ~1.0', 'Could not parse weight values from calculateFeasibilityScore');
  }
}

// ============================================================================
// TEST 5: Budget Container IDs in HTML
// ============================================================================
function testBudgetContainers() {
  console.log('\n--- Budget Container IDs ---');
  var htmlPath = path.join(CONFIG.basePath, CONFIG.htmlFile);
  if (!fs.existsSync(htmlPath)) {
    assert(false, 'index.html exists', 'File not found');
    return;
  }

  var htmlContent = fs.readFileSync(htmlPath, 'utf8');

  var requiredContainers = [
    'budgetAlignmentContainer', 'budgetAllocationTracker',
    'budgetTrackingContainer', 'budgetDashboardContainer', 'budgetProgressSidebar'
  ];

  var foundCount = 0;
  requiredContainers.forEach(function(id) {
    if (htmlContent.includes('id="' + id + '"') || htmlContent.includes("id='" + id + "'")) {
      foundCount++;
      assert(true, 'Container exists: ' + id);
    } else {
      assert(false, 'Container exists: ' + id, 'Not found in HTML');
    }
  });

  console.log('\nBudget Containers Summary: ' + foundCount + '/' + requiredContainers.length + ' found\n');
}

// ============================================================================
// TEST 6: Budget Calculation Integrity
// ============================================================================
function testBudgetIntegrity() {
  console.log('\n--- Budget Calculation Integrity ---');
  var setupPath = path.join(CONFIG.basePath, CONFIG.budgetSetupFile);
  var content = fs.readFileSync(setupPath, 'utf8');

  // Check for total calculation logic
  var hasTotalCalc = content.includes('total') && content.includes('budget');
  assert(hasTotalCalc, 'Total budget calculation present');

  // Check for per-item calculations
  var hasPerItemCalc = content.includes('allocation') || content.includes('percentage');
  assert(hasPerItemCalc, 'Per-item allocation calculation present');

  // Check for validation logic
  var hasValidation = content.includes('validate') || content.includes('check') || content.includes('error');
  assert(hasValidation, 'Budget validation logic present');
}

